#!/usr/bin/env python3
"""
encode-real-model-hfstream.py — GKQ v2 encoder that streams safetensors
shards directly from HuggingFace Hub, ONE SHARD AT A TIME, deleting each
shard from the local cache after its tensors have been encoded.

Why this exists: encode-real-model-streaming.py still requires the full
HF snapshot on disk (it just doesn't load the whole model into RAM).
Qwen2.5-72B is ~145 GB in safetensors — does not fit on a workstation
with 46 GB free. This encoder fetches one shard, processes every tensor
in it, removes the shard, and proceeds to the next. Peak disk = one
shard (~5 GB for Qwen2.5-72B) + the growing output file.

Two passes:
  Pass 1: walk the shard index (no payloads) to inventory tensors and
          compute exact (num_spectral, num_dense) counts for the header.
          When `model.safetensors.index.json` is present (multi-shard),
          we read just THAT file. When it's not, we fall back to fetching
          each shard's safetensors header (~few hundred KB via Range,
          but we don't reimplement the protocol — we let safetensors do
          a normal open after `hf_hub_download`, then delete the shard
          before moving on).
  Pass 2: per-shard encode. For each shard:
            - hf_hub_download (cache_dir bounded)
            - open with safetensors.safe_open
            - for every tensor in the shard:
                  classify (spectral / dense)
                  read get_tensor → encode → write to output
            - close, remove shard file, free disk

Write order: GKQ v2 requires the on-disk layout to be
  [header] [num_spectral spectral blocks] [num_dense dense blocks]
so we cannot interleave spectral and dense as we encounter them in
each shard. The encoder writes spectral blocks to a temp file and
dense blocks (sans aliases) to a second temp file as it walks each
shard; after the last shard we splice
    final = header + spectral_tmp + dense_tmp + alias_blocks
and remove the temp files. Within each section the order is shard
order followed by safetensors `keys()` order — NOT canonical-name
sort like encode-real-model-streaming.py — but the reader is
name-indexed so this is semantically equivalent.

Usage:
    python3 encode-real-model-hfstream.py \\
        --model Qwen/Qwen2.5-72B-Instruct \\
        --output rknots/qwen-72b-gkq.knot \\
        --rank 64

Optional safety knob: --max-shard-disk-gb N (default 30). If we ever
see /tmp free drop below this, we abort with a clear message rather
than filling the disk.
"""

from __future__ import annotations

import argparse
import json
import os
import shutil
import sys
import time
from pathlib import Path
from typing import Dict, List, Optional, Tuple

import numpy as np

# Reuse mapping + writer + spectral quantizer from the streaming encoder.
_HERE = Path(__file__).resolve().parent
sys.path.insert(0, str(_HERE))
import gkq_v2_format as gkq  # noqa: E402

import importlib.util  # noqa: E402

_legacy_spec = importlib.util.spec_from_file_location(
    "encode_real_model_legacy", str(_HERE / "encode-real-model.py")
)
_legacy = importlib.util.module_from_spec(_legacy_spec)
_legacy_spec.loader.exec_module(_legacy)  # type: ignore[union-attr]

map_tensor_name = _legacy.map_tensor_name
detect_arch = _legacy.detect_arch
build_knot_config = _legacy.build_knot_config
_spectral_quantize = _legacy._spectral_quantize


# ─────────────────────────────────────────────────────────────────────────────
# HF discovery: list shards + download a single small file (config / index)
# ─────────────────────────────────────────────────────────────────────────────


def _list_shards(model_id: str) -> List[str]:
    """Return the list of *.safetensors file names in the repo, sorted."""
    from huggingface_hub import HfApi
    api = HfApi()
    files = api.list_repo_files(model_id)
    shards = sorted(f for f in files if f.endswith(".safetensors"))
    if not shards:
        raise FileNotFoundError(
            f"no *.safetensors found in repo {model_id!r}"
        )
    return shards


def _download_one(model_id: str, filename: str, cache_dir: str) -> str:
    from huggingface_hub import hf_hub_download
    return hf_hub_download(
        repo_id=model_id,
        filename=filename,
        cache_dir=cache_dir,
    )


def _load_hf_config_from_hub(model_id: str, cache_dir: str):
    """Pull config.json and parse it (prefer transformers.AutoConfig)."""
    cfg_path = _download_one(model_id, "config.json", cache_dir)
    try:
        from transformers import AutoConfig  # type: ignore
        cfg = AutoConfig.from_pretrained(str(Path(cfg_path).parent))
        print("[hfstream] config: transformers.AutoConfig")
        return cfg
    except Exception as e:
        print(f"[hfstream] config: raw config.json fallback ({e})")
    with open(cfg_path) as f:
        cfg_dict = json.load(f)

    class _Cfg:
        pass
    cfg = _Cfg()
    for k, v in cfg_dict.items():
        setattr(cfg, k, v)
    return cfg


def _load_shard_index(model_id: str, cache_dir: str) -> Optional[Dict[str, str]]:
    """Return tensor_name → shard_filename from model.safetensors.index.json
    when present (multi-shard models). Returns None for single-shard repos.
    """
    try:
        index_path = _download_one(
            model_id, "model.safetensors.index.json", cache_dir
        )
    except Exception:
        return None
    with open(index_path) as f:
        idx = json.load(f)
    return idx.get("weight_map", {})


# ─────────────────────────────────────────────────────────────────────────────
# Disk safety
# ─────────────────────────────────────────────────────────────────────────────


def _free_gb(path: str) -> float:
    s = shutil.disk_usage(path)
    return s.free / (1024 ** 3)


def _assert_disk(path: str, min_gb: float, where: str) -> None:
    free = _free_gb(path)
    if free < min_gb:
        raise RuntimeError(
            f"disk failsafe tripped at {where}: free={free:.1f} GB < {min_gb:.1f} GB"
        )


# ─────────────────────────────────────────────────────────────────────────────
# Per-shard encode
# ─────────────────────────────────────────────────────────────────────────────


def _bf16_to_f32_numpy(t):
    import torch
    if t.dtype == torch.bfloat16:
        t = t.to(torch.float32)
    return t.detach().cpu().numpy()


# GKQ v2's write_dense_tensor packs `len(raw_bytes)` as <u32. A dense block
# whose payload exceeds 4 GiB therefore cannot be written — which happens on
# 70B+ models where the embedding alone is vocab_size × hidden_size × 4
# (e.g. Qwen2.5-72B: 152064 × 8192 × 4 = 4.98 GiB). For those tensors we
# downcast bf16 → f16 (halves the byte count) before handing the array to
# the writer. bf16 has a wider exponent range than f16 (8-bit vs 5-bit
# exponent), so this is technically lossy: values with |x| > 65504 saturate
# to inf, and very small values lose subnormal precision. Embeddings and
# norms practically live well inside f16 range, so this is safe in
# practice. We log every demotion so the operator sees it.
_F32_MAX_DENSE_BYTES = 4 * 1024 * 1024 * 1024 - 1  # writer cap


def _preserve_dtype_numpy(t, canonical_name: str = ""):
    import torch
    src_dtype = t.dtype
    nbytes_f32 = t.numel() * 4
    if t.dtype == torch.bfloat16:
        # Default: promote to f32 (preserves the bf16 range exactly because
        # bf16 ⊂ f32 — both have an 8-bit exponent).
        if nbytes_f32 > _F32_MAX_DENSE_BYTES:
            t = t.to(torch.float16)
            print(f"[hfstream] dense tensor {canonical_name!r} exceeds 4 GiB as "
                  f"f32 ({nbytes_f32 / 1e9:.2f} GB); demoted bf16 → f16 to fit "
                  "the writer's u32 length field. Saturates |x|>65504.",
                  flush=True)
        else:
            t = t.to(torch.float32)
    elif src_dtype == torch.float32 and nbytes_f32 > _F32_MAX_DENSE_BYTES:
        t = t.to(torch.float16)
        print(f"[hfstream] dense tensor {canonical_name!r} f32 payload "
              f"{nbytes_f32 / 1e9:.2f} GB exceeds 4 GiB; demoted to f16.",
              flush=True)
    return t.detach().cpu().numpy()


def _classify_repo_tensors(
    weight_map: Dict[str, str],
    max_layers: Optional[int],
    tie_word_embeddings: bool,
) -> Tuple[int, int, List[Tuple[str, str]]]:
    """Pre-classify every repo tensor without loading any payload.

    Returns (num_spectral, num_dense, aliases) where aliases is
    [(alias_canonical, target_canonical), ...] (will always be ≤1).
    """
    seen_canonical: Dict[str, str] = {}  # canonical → kind
    for hf_name in weight_map:
        mapped = map_tensor_name(hf_name, max_layers)
        if mapped is None:
            continue
        canonical, kind = mapped
        if canonical in seen_canonical:
            continue
        seen_canonical[canonical] = kind

    aliases: List[Tuple[str, str]] = []
    embed_canon = "token_embd.weight"
    out_canon = "output.weight"
    if tie_word_embeddings:
        if embed_canon in seen_canonical and out_canon not in seen_canonical:
            aliases.append((out_canon, embed_canon))
            seen_canonical[out_canon] = "dense"  # accounted for in num_dense
        elif embed_canon in seen_canonical and out_canon in seen_canonical:
            # Both present: drop the duplicate, emit alias.
            del seen_canonical[out_canon]
            seen_canonical[out_canon] = "dense"
            aliases.append((out_canon, embed_canon))

    num_spectral = sum(1 for k in seen_canonical.values() if k == "spectral")
    num_dense = sum(1 for k in seen_canonical.values() if k == "dense")
    return num_spectral, num_dense, aliases


def encode_hfstream(
    *,
    model_id: str,
    model_name: str,
    output_path: str,
    max_layers: Optional[int],
    rank: int,
    cache_dir: str,
    min_free_gb: float,
) -> dict:
    """Pass 1: inventory via index + config. Pass 2: per-shard encode."""
    t_start = time.time()
    # ── Config + arch ───────────────────────────────────────────────────────
    hf_config = _load_hf_config_from_hub(model_id, cache_dir)
    arch = detect_arch(hf_config)
    knot_config = build_knot_config(hf_config, arch, max_layers)
    tie_word_embeddings = bool(getattr(hf_config, "tie_word_embeddings", False))

    # ── Shard inventory ────────────────────────────────────────────────────
    shards = _list_shards(model_id)
    print(f"[hfstream] {len(shards)} shards in {model_id}")

    weight_map = _load_shard_index(model_id, cache_dir)
    if weight_map is None:
        # Single-shard repo: we need to peek inside to enumerate tensors.
        # Download the single shard now and keep it (we'll process it in
        # pass 2 anyway). This is fine because single-shard models are
        # small enough to fit (otherwise they'd have been sharded).
        if len(shards) != 1:
            raise RuntimeError(
                "multi-shard repo missing model.safetensors.index.json; "
                "cannot inventory tensors without downloading all shards"
            )
        local = _download_one(model_id, shards[0], cache_dir)
        from safetensors import safe_open
        weight_map = {}
        with safe_open(local, framework="pt", device="cpu") as f:
            for tn in f.keys():
                weight_map[tn] = shards[0]
        # Don't delete; pass 2 will reuse this shard.
        _preloaded = {shards[0]: local}
    else:
        _preloaded = {}

    print(f"[hfstream] {len(weight_map)} repo tensors across "
          f"{len(set(weight_map.values()))} shard files")

    num_spectral, num_dense, aliases = _classify_repo_tensors(
        weight_map, max_layers, tie_word_embeddings
    )
    print(f"[hfstream] arch={arch} tie_word_embeddings={tie_word_embeddings}")
    print(f"[hfstream] classified: {num_spectral} spectral, "
          f"{num_dense} dense (incl. {len(aliases)} alias)")
    print(f"[hfstream] spectral rank: {rank}")

    # Invert weight_map: shard_filename → list of (hf_name)
    shard_tensors: Dict[str, List[str]] = {}
    for tn, shard in weight_map.items():
        shard_tensors.setdefault(shard, []).append(tn)

    # ── Open output + spectral/dense temp files ────────────────────────────
    out_path = Path(output_path)
    out_path.parent.mkdir(parents=True, exist_ok=True)
    spectral_tmp = out_path.with_suffix(out_path.suffix + ".spectral.tmp")
    dense_tmp = out_path.with_suffix(out_path.suffix + ".dense.tmp")
    worst_err = 0.0
    worst_err_name = ""
    spectral_bytes = 0
    dense_bytes = 0
    written_canonical: set = set()
    peak_shard_disk = 0
    peak_total_disk_used = 0
    cache_root = Path(cache_dir)
    alias_set = {a for a, _ in aliases}

    with open(spectral_tmp, "wb") as f_spec, open(dense_tmp, "wb") as f_dense:
        for shard_idx, shard_name in enumerate(sorted(shard_tensors)):
            _assert_disk(cache_dir, min_free_gb, f"before shard {shard_name}")
            if shard_name in _preloaded:
                local = _preloaded[shard_name]
            else:
                t_dl = time.time()
                local = _download_one(model_id, shard_name, cache_dir)
                dl_s = time.time() - t_dl
                try:
                    shard_sz = os.path.getsize(local)
                    peak_shard_disk = max(peak_shard_disk, shard_sz)
                    print(f"[hfstream] shard {shard_idx + 1}/{len(shard_tensors)} "
                          f"{shard_name}  size={shard_sz / 1e9:.2f} GB  "
                          f"dl={dl_s:.1f}s  free={_free_gb(cache_dir):.1f} GB",
                          flush=True)
                except OSError:
                    pass

            from safetensors import safe_open
            with safe_open(local, framework="pt", device="cpu") as f:
                for hf_name in f.keys():
                    mapped = map_tensor_name(hf_name, max_layers)
                    if mapped is None:
                        continue
                    canonical, kind = mapped
                    if canonical in written_canonical:
                        continue
                    # If this canonical is going to be emitted as an alias,
                    # skip its payload entirely (alias section emits it
                    # at the end pointing at the target).
                    if canonical in alias_set:
                        continue
                    t = f.get_tensor(hf_name)
                    if kind == "spectral":
                        arr = _bf16_to_f32_numpy(t)
                        del t
                        arr = np.ascontiguousarray(arr, dtype=np.float32)
                        if arr.ndim != 2:
                            arr = arr.reshape(arr.shape[0], -1)
                        (u_q8, sigma_q8, v_q8, u_max, sigma_max, v_max,
                         d_out, d_in, rel_err, eff_rank) = _spectral_quantize(
                            arr, rank=rank
                        )
                        del arr
                        if rel_err > worst_err:
                            worst_err = rel_err
                            worst_err_name = canonical
                        before = f_spec.tell()
                        gkq.write_spectral_tensor(
                            f_spec, canonical, u_q8, sigma_q8, v_q8,
                            u_max, sigma_max, v_max, d_out, d_in,
                            rank=eff_rank,
                        )
                        spectral_bytes += f_spec.tell() - before
                        del u_q8, sigma_q8, v_q8
                    else:
                        arr = _preserve_dtype_numpy(t, canonical)
                        del t
                        if arr.dtype not in (np.float16, np.float32):
                            arr = arr.astype(np.float32)
                        arr = np.ascontiguousarray(arr)
                        before = f_dense.tell()
                        gkq.write_dense_tensor(f_dense, canonical, arr)
                        dense_bytes += f_dense.tell() - before
                        del arr
                    written_canonical.add(canonical)

            # Done with this shard: delete from local cache to free disk.
            # hf_hub_download stores the blob behind a symlink in
            # snapshots/<rev>/<file>; remove the underlying blob too.
            try:
                real = os.path.realpath(local)
                if os.path.exists(real):
                    os.remove(real)
                if os.path.islink(local):
                    os.unlink(local)
                elif os.path.exists(local) and real != local:
                    os.remove(local)
            except OSError as e:
                print(f"[hfstream] WARN: could not remove {local}: {e}")
            # Track peak used disk under cache after cleanup attempt.
            try:
                total = 0
                for root, _dirs, fs in os.walk(cache_root):
                    for fn in fs:
                        try:
                            total += os.path.getsize(os.path.join(root, fn))
                        except OSError:
                            pass
                peak_total_disk_used = max(peak_total_disk_used, total)
            except OSError:
                pass

        # Aliases (must reference an already-written target). Targets live
        # in the dense_tmp file; aliases are appended to it.
        for alias_name, alias_target in sorted(aliases):
            before = f_dense.tell()
            gkq.write_dense_alias(f_dense, alias_name, alias_target)
            dense_bytes += f_dense.tell() - before

    # Splice: header → spectral_tmp → dense_tmp.
    with open(out_path, "wb") as out:
        gkq.write_header(
            out, model_name, arch, knot_config, num_spectral, num_dense
        )
        for tmp in (spectral_tmp, dense_tmp):
            with open(tmp, "rb") as tf:
                shutil.copyfileobj(tf, out, length=4 * 1024 * 1024)
    # Cleanup temps.
    for tmp in (spectral_tmp, dense_tmp):
        try:
            os.remove(tmp)
        except OSError:
            pass

    elapsed = time.time() - t_start
    file_size = out_path.stat().st_size
    return {
        "output_path": str(out_path),
        "file_size_bytes": file_size,
        "file_size_mb": file_size / 1e6,
        "num_spectral": num_spectral,
        "num_dense": num_dense,
        "spectral_bytes": spectral_bytes,
        "dense_bytes": dense_bytes,
        "spectral_pct": 100.0 * spectral_bytes / max(file_size, 1),
        "dense_pct": 100.0 * dense_bytes / max(file_size, 1),
        "worst_reconstruction_error": worst_err,
        "worst_reconstruction_error_name": worst_err_name,
        "elapsed_seconds": elapsed,
        "peak_shard_bytes": peak_shard_disk,
        "peak_cache_bytes_post_cleanup": peak_total_disk_used,
    }


def _print_summary(s: dict) -> None:
    print("─" * 64)
    print(f"GKQ v2 file written: {s['output_path']}")
    print(f"  size:               {s['file_size_mb']:.2f} MB "
          f"({s['file_size_bytes']:,} bytes)")
    print(f"  spectral tensors:   {s['num_spectral']}  "
          f"({s['spectral_pct']:.1f}% of file, {s['spectral_bytes']:,} bytes)")
    print(f"  dense tensors:      {s['num_dense']}  "
          f"({s['dense_pct']:.1f}% of file, {s['dense_bytes']:,} bytes)")
    print(f"  worst SVD rel-err:  {s['worst_reconstruction_error']:.4f}  "
          f"({s['worst_reconstruction_error_name']})")
    print(f"  encode wall-time:   {s['elapsed_seconds']:.1f}s")
    print(f"  peak shard size:    {s['peak_shard_bytes'] / 1e9:.2f} GB")
    print(f"  peak cache(post-rm):{s['peak_cache_bytes_post_cleanup'] / 1e9:.2f} GB")
    print("─" * 64)


# ─────────────────────────────────────────────────────────────────────────────
# CLI
# ─────────────────────────────────────────────────────────────────────────────


def parse_args(argv=None):
    p = argparse.ArgumentParser(
        description="HF-streaming GKQ v2 encoder — one shard at a time."
    )
    p.add_argument("--model", required=True, help="HF model id")
    p.add_argument("--output", required=True, help="Output .knot path")
    p.add_argument("--model-name", default=None,
                   help="Override model name in header (default: --model)")
    p.add_argument("--max-layers", type=int, default=None)
    p.add_argument("--rank", type=int, default=gkq.RANK_DEFAULT)
    p.add_argument("--cache-dir", default="/tmp/hf-stream-cache")
    p.add_argument("--min-free-gb", type=float, default=10.0,
                   help="Abort if free disk drops below this (failsafe)")
    return p.parse_args(argv)


def main(argv=None) -> int:
    args = parse_args(argv)
    Path(args.cache_dir).mkdir(parents=True, exist_ok=True)
    summary = encode_hfstream(
        model_id=args.model,
        model_name=args.model_name or args.model,
        output_path=args.output,
        max_layers=args.max_layers,
        rank=args.rank,
        cache_dir=args.cache_dir,
        min_free_gb=args.min_free_gb,
    )
    _print_summary(summary)
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
